var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"휴가 중에 이런 곳으로 불러내서 죄송해요.","JPN":"休暇中にこんなところまで呼び出してすみませんね。","ENG":"Sorry for calling you out here during your leave.","TWN":"很抱歉在休假期間把妳叫到這種地方。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"범죄자만 잡을 수 있다면, 난 아무래도 상관없어.","JPN":"犯罪者さえ捕まえられるなら、私は別に構わない。","ENG":"I don't mind as long as we can catch some criminals.","TWN":"只要能抓到罪犯，我是無所謂啦。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그래서, 무슨 일이야?","JPN":"それで、どうしたの？","ENG":"So, what is it?","TWN":"所以，發生什麼事情了？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"간략히 브리핑을 해드리자면, 용의자는 <color=#ffd34c>민병대</color>라고 불리는 무장 조직의 일원이에요.","JPN":"簡単に状況を説明すると、容疑者は<color=#ffd34c>民兵隊</color>と呼ばれる武装組織の一員です。","ENG":"To give you a quick briefing, the suspect is a member of an armed group called <color=#ffd34c>The Militia</color>.","TWN":"簡略地說明一下，嫌犯是被稱為 <color=#ffd34c>民兵</color>的武裝組織成員。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"카운터들만을 골라서 사냥하는 사람들이죠.","JPN":"カウンターのみを狙って狩る者たちです。","ENG":"They specialize in hunting down Counters.","TWN":"是一群只狩獵制裁者的人。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......뭐? 카운터를? 어째서?","JPN":"……何？　カウンターを？　なぜ？","ENG":"What? Counters? Why?","TWN":"……什麼？狩獵制裁者？為什麼？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"민병대라는 조직은 원래 카운터 범죄의 피해자들이 결성한 조직이었거든요.","JPN":"民兵隊という組織は、元々カウンター犯罪に遭った被害者たちが結成した組織なんです。","ENG":"The Militia was initially founded by the victims of Counter crime.","TWN":"民兵這個組織，本來是由制裁者犯罪的受害者所組成的。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"어때요? 꽤 익숙한 사연이죠?","JPN":"どうですか？　聞いたことあるような話でしょう？","ENG":"Well? Doesn't that sound quite familiar?","TWN":"怎麼樣？很熟悉的故事吧？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"흥, 나랑 비교라도 할 생각이라면 틀렸어.","JPN":"ふん、私と比べるつもりなら失礼よ。","ENG":"Hmpf, don't even think about comparing them to me.","TWN":"哼，如果妳把我和那些傢伙相提並論，那妳就大錯特錯了。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그 녀석들은 범죄조직이고, 난 경찰이라고!","JPN":"あいつらは犯罪組織で、私は警察だから！","ENG":"They're just a crime syndicate. I'm a police officer!","TWN":"那些傢伙是犯罪集團，我是警察！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 맞아요. 민병대도 처음엔 카운터 범죄를 막기 위해 만들어진 자경조직이었지만......","JPN":"はは、そうですね。初めは民兵隊も、カウンターの犯罪を防ぐため作られた自警組織でしたが……","ENG":"Hah hah, you're right. The Militia started off as a group of vigilantes trying to stop Counter crime...","TWN":"哈哈，沒錯。民兵一開始，也是為了防止制裁者犯罪所成立的自衛組織……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"언젠가부터 행동이 과격해지더니 지금은 사적 제재를 일삼는 완전한 불법 단체가 되어 버렸어요.","JPN":"いつの間にか行動が過激になり、現在は私的制裁を加える違法団体になってしまいました。","ENG":"But they grew increasingly violent over time. Now they're a completely illegal organization that hunt Counters for revenge.","TWN":"不知道什麼時候開始，他們的行為越來越暴力，現在已經完全變成了動用私刑的非法團體。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"거기다 암암리에 민병대를 숨겨주며 협조하는 사람들도 많다 보니 꼬리를 잡기가 쉽지 않았죠.","JPN":"それに、こっそり民兵隊を匿う協力者も多いので、なかなか尻尾を掴みにくいのが現状です。","ENG":"It was tough tracking them down because they have a lot of supporters who help conceal them.","TWN":"再加上還有很多願意暗中藏匿他們，從中協助的人，所以很難抓住他們的尾巴。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"하지만, 이번엔 단서를 잡았다는 거지?","JPN":"でも、今回は手がかりが見つかったのよね？","ENG":"But we found a lead this time?","TWN":"不過這次有線索了吧？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"네, 이번에 민병대의 주요 멤버가 이 근처에 나타날 거라는 정보가 입수됐거든요.","JPN":"はい。民兵隊の主要メンバーが、この近くに現れるという情報を入手しました。","ENG":"Yes. I've got intel that a key member of the Militia will be appearing around here.","TWN":"是的，有情報說民兵的主要成員在這附近出沒。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"녀석들의 의도야 어찌됐건 난 상관없어.","JPN":"やつらの意図など、私には関係ない。","ENG":"I couldn't care less whether they mean well or not.","TWN":"我才不在乎犯人的動機是什麼。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"범죄자인 이상 봐주지 않을 거니까.","JPN":"犯罪者である以上、手加減はしないから。","ENG":"They're criminals in my book, and I'm not going to go easy on them.","TWN":"只要是罪犯一律逮捕。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"......조심하세요 경정님. 민병대는 카운터를 사냥하는 조직이니까요.","JPN":"……気をつけてください。民兵隊はカウンターを狩る組織ですから。","ENG":"Be careful though, Major. The Militia specializes in hunting down Counters.","TWN":"……請小心點，警正大人。畢竟民兵是專門狩獵制裁者的組織。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그게 무슨 뜻인지 아시겠어요?","JPN":"それがどういう意味かわかりますか？","ENG":"You realize what that means?","TWN":"妳知道這代表什麼意思嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그러고 보니...... 대체 카운터들이 어떻게 녀석들에게 당한다는 거야?","JPN":"そういえば……カウンターがやられるなんて変ね。","ENG":"Oh... Come to think of it... How do they even manage to take Counters down?","TWN":"這麼說來……制裁者到底是怎麼被他們打敗的？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"민병대는 기껏해야 일반인들일 거 아냐?","JPN":"民兵隊とは言っても、たかが一般人でしょう？","ENG":"Aren't they all non-powered?","TWN":"民兵頂多是些普通人吧？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"민병대는 수단과 방법을 가리지 않아요.","JPN":"民兵隊は手段と方法を選びませんよ。","ENG":"The Militia uses any means necessary to carry out their objectives.","TWN":"因為民兵會不擇手段。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"기습에 자폭, 부비트랩에 화학무기까지......","JPN":"奇襲に自爆、ブービートラップ、化学兵器まで……","ENG":"Everything from ambushes to suicide bombing, booby traps, and chemical weapons...","TWN":"從偷襲到自爆，詭雷陷阱到化學武器……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"카운터를 쓰러트릴 수만 있다면 무슨 짓이든 하죠.","JPN":"カウンターを倒すためなら、何だってします。","ENG":"They're willing to do anything as long as they can kill Counters.","TWN":"只要能擊敗制裁者，那些人什麼都做得出來。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아무리 카운터라고 해도 방심했다간......","JPN":"いくらカウンターでも油断すれば……","ENG":"Even if you're a Counter, you shouldn't underestimate them, or else...","TWN":"就算是制裁者，一不小心也會……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L32_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"저격입니다! 엎드려요, 경정님!!","JPN":"狙撃です！　伏せて！！","ENG":"Sniper! Get down, Major!","TWN":"有狙擊！趴下，警正！！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"크윽...... 이 자식들이......","JPN":"くうっ……あいつら……","ENG":"Ugh... Those jerks...","TWN":"唔……那群傢伙……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"경정님! 괜찮아요? 피가 나는데......","JPN":"警視様！　大丈夫ですか？　血が……","ENG":"Major! You alright? You're bleeding...","TWN":"警正大人！沒事吧？妳流血了……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그냥 스쳤어. 이 정도는 아무것도 아니야!","JPN":"ただのかすり傷よ。これくらい、どうってことない！","ENG":"It only grazed me. This is nothing!","TWN":"只是擦傷而已，這種小傷根本不算什麼！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"차를 완전히 관통할 정도의 위력을 가진 탄환이라니......","JPN":"車を貫通するほどの威力を持つ弾丸だなんて……","ENG":"That round was powerful enough to penetrate the car completely...","TWN":"子彈的威力竟然能夠完全貫穿汽車……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이런 걸 맞았다간 카운터라도 위험하겠는데요?","JPN":"こんなので撃たれたらカウンターでも命が危ないかもしれません。","ENG":"Even a Counter won't be able to survive that.","TWN":"被這種子彈打中，就算是制裁者也很不妙吧。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"일단 숨어서 저격수의 위치를 파악해야......","JPN":"とりあえず、隠れて狙撃手の位置を把握しないと……","ENG":"We should take cover and try to locate the sniper...","TWN":"我們得先躲起來，掌握狙擊手的位置……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"이미 걸렸는데 숨어봤자 뭐해?","JPN":"位置もバレてるし、隠れても無駄よ！","ENG":"What's the point of hiding when they've already found us?","TWN":"都已經被發現了，躲起來是有什麼用？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L43_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"걱정 마. 범죄자들을 내가 다 쓸어버리고 올 테니까!","JPN":"心配しないで。私が始末してくるから！","ENG":"Don't worry. I'll go take them all down!","TWN":"別擔心。我會把罪犯全部一網打盡的！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"경정님! 갑자기 뛰어나가시면 위험해요!","JPN":"警視様！　いきなり飛び出したら危険ですよ！","ENG":"Major! It's too dangerous to rush out like that!","TWN":"警正大人！突然跑出去很危險的啊！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"경정님!!","JPN":"警視様！！","ENG":"Major!","TWN":"警正大人！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이런!!","JPN":"おっと！？","ENG":"Dang it!","TWN":"快回來！！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"발포음이 희미한 걸로 봐선 적어도 500미터는 떨어진 곳에서 쏘고 있다는 건데......","JPN":"微かな発砲音。つまり射撃地点は、少なくとも500メートル以上離れた場所か……","ENG":"Considering the faint sound of the gunshot, they're at least 500 meters away...","TWN":"從槍聲很微弱這點來看，至少是在500公尺外的地方射擊的……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"고도의 훈련을 받은 저격수인 건가? 아니면......","JPN":"高度な訓練を受けた狙撃手なのかな？　それとも……","ENG":"Is it a highly trained sniper? Or could it be...","TWN":"是個訓練有素的狙擊手嗎？還是說……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_AP_QM","text":{"KOREA":"방해꾼이 있다고 해서 와봤더니...... 경찰이었나.","JPN":"邪魔者は警察だったのか……","ENG":"I was told there were obstacles that needed to be removed here... But I didn't know you're cops.","TWN":"我聽說有阻礙者才到這裡來的……原來是警察嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_AP_QM","text":{"KOREA":"우리의 목적은 이 곳에 숨어 있는 더러운 카운터 범죄자 놈을 단죄하는 거다.","JPN":"俺たちの目的は、ここに隠れている汚らわしいカウンター犯罪者を断罪することだ。","ENG":"Our goal is to make the dirty Counter criminal hiding here pay for his crimes.","TWN":"我們的目的是審判躲在這裡的骯髒制裁者罪犯。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_AP_QM","text":{"KOREA":"경찰을 해치고 싶지는 않아.","JPN":"警察にケガをさせるつもりはない。","ENG":"I don't want to hurt any cops.","TWN":"我不想傷害警察。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_AP_QM","text":{"KOREA":"그러니 내 동료가 일을 마칠 때까지 그 자리에서 움직이지 마라.","JPN":"だから俺の仲間が任務を終えるまで、その場所から動くな。","ENG":"So stay put until my colleague is done with our business.","TWN":"所以，在我的同伴完成任務之前，妳就乖乖地待在這裡別動。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 협박을 당했다고 가만히 있다간 경찰 봉급을 받을 염치가 없는데 말이죠.","JPN":"はは。脅されて大人しく言うことを聞いてたら、お給料をもらう意味がありません。","ENG":"Hah hah, if I did as I was told just because someone threatened me, I'm not sure if I could cash my next police paycheck in good conscience.","TWN":"哈哈哈，如果受到威脅就乖乖不動，有什麼臉去拿警察的薪水啊。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"지금이라도 자수해서 광명 찾으시는 게 어때요?","JPN":"今からでも間に合うので、自首をお勧めします。","ENG":"Why don't you turn yourself before it's too late?","TWN":"現在就自首，重新做人怎麼樣？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"제가 기소의견서 잘 써드릴게요.","JPN":"なるべく穏便な処置で済むように、処分意見書を書くので。","ENG":"I'll be sure to put in a good word for you on the statement.","TWN":"我會幫你寫起訴意見書的。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_AP_QM","text":{"KOREA":"......총구가 머리에 닿은 상황에서도 여유를 부리는 건가?","JPN":"……頭に銃を突きつけられているのに、ずいぶん落ち着いてるな。","ENG":"You've got some nerve joking around even with a gun to your head...","TWN":"……被槍抵著頭還這麼有餘裕嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_AP_QM","text":{"KOREA":"정말이지, 너란 애는 하나도 변하질 않는구나.","JPN":"お前ってやつは、相変わらずだな。","ENG":"Really, you haven't changed one bit, have you?","TWN":"真是的，妳這孩子還真是一點都沒變呢。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"뭐라고요?","JPN":"え？","ENG":"What?","TWN":"你說什麼？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"가만, 그러고 보니 이 목소리......?","JPN":"あれ？　そういえば、この声……？","ENG":"Hang on... that voice?","TWN":"等一下，這個聲音是……？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"설마...... 팀장님?","JPN":"まさか……班長ですか？","ENG":"Could it be... Boss?","TWN":"難道是……隊長？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"어이! 끝났어! 철수할 시간이다! 빨리 올라타!","JPN":"おい！　終わったぞ！　撤収だ！　早く乗れ！","ENG":"Hey! It's over! Let's get out of here! Hop in!","TWN":"喂！結束了！該撤退了！快上車！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_AP_QM","text":{"KOREA":"......알겠다.","JPN":"……わかった。","ENG":"Copy...","TWN":"……知道了。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"잠깐 기다려요! 팀장님! 정말 팀장님 맞아요?!!","JPN":"ちょっと待ってください！　班長！　本当に班長なんですか！？","ENG":"Wait! Boss! Is that really you?!!","TWN":"等一下！隊長！是隊長沒錯吧？！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"크윽!!","JPN":"くうっ！？","ENG":"Hngh!!","TWN":"唔！！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"KYLE_DELTA_AP_QM","text":{"KOREA":"돌아가, 경위. 네 팀장은 죽었어.","JPN":"戻れ、警部補。お前の班長はもう死んだ。","ENG":"Go back, Lieutenant. Your team leader is dead.","TWN":"回去吧，警衛。妳的隊長已經死了。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"KYLE_DELTA_AP_QM","text":{"KOREA":"여기에 있는 건 그냥 복수에 미친 범죄자일 뿐이야.","JPN":"ここにいるのは、復讐に飢えたただの犯罪者だけだ。","ENG":"All you see here is a crazy criminal hell-bent on revenge.","TWN":"在妳眼前的，只是個為復仇發狂的犯罪者而已。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"KYLE_DELTA_AP_QM","text":{"KOREA":"그러니까...... 다신 마주치는 일이 없었으면 좋겠군.","JPN":"だから……二度と会わないことを祈る。","ENG":"So... I hope we never have to see each other again.","TWN":"所以……希望我們不會再見面了。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_20"},{"id":"L35_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"잠깐만요! 기다려요, 팀장님!!","JPN":"待ってください！　班長！！","ENG":"Wait! Wait, boss!","TWN":"等等！請等一下，隊長！！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};